//! HiFi-GAN-class neural vocoder (Pneuma TTS, Track B).
//!
//! Reference: arXiv 2010.05646 (HiFi-GAN — Generative Adversarial Networks
//! for Efficient and High Fidelity Speech Synthesis, Kong et al. 2020).
//! https://arxiv.org/abs/2010.05646
//!
//! Consumes a mel-spectrogram (`n_mels=80`, `n_frames`) produced by the
//! acoustic model (Track A) and emits f32 PCM at the configured sample rate
//! (22 050 Hz for the Piper / VITS-small defaults).
//!
//! Pipeline (matches HiFi-GAN V1 generator):
//! 1. Initial conv1d: in=80, out=initial_channels, k=7, pad=3
//! 2. For each upsample stage `i` (length = `upsample_rates.len()`):
//!    - leaky_relu(0.1)
//!    - conv_transpose1d(stride=upsample_rates[i], k=upsample_kernel_sizes[i],
//!      pad=(k - stride)/2)
//!    - Multi-Receptive-Field (MRF) fusion: average of `resblock_kernels.len()`
//!      ResBlock1 outputs. Each ResBlock1 stacks `resblock_dilations[k_idx]`
//!      sub-blocks; each sub-block is
//!         leaky_relu → conv1d(k, dilation=d) → leaky_relu → conv1d(k, dilation=1)
//!         + residual.
//! 3. Final: leaky_relu → conv1d(in=final_channels, out=1, k=7, pad=3) → tanh
//!
//! Channel reduction: each upsample stage halves the channel count, so the
//! final conv consumes `initial_channels >> upsample_rates.len()` channels.
//! For the V1 default (`initial_channels=512`, 4 stages), that's 32 channels.
//!
//! Buffers are NOT pre-allocated as a fixed scratch (unlike the encoder)
//! because the time axis grows by `prod(upsample_rates)` and the input
//! `n_frames` is not known at construction. We allocate per-forward; the
//! cost is dominated by the conv math anyway. A future optimisation could
//! pool buffers once a maximum `n_frames` is fixed.
//!
//! Tensor name convention (matches the spec in PNEUMA_PHASE_2):
//!   `vocoder_conv_pre.{weight,bias}`
//!   `vocoder_ups_{i}.{weight,bias}`                    — transposed conv per stage
//!   `vocoder_res_{i}_{j}_conv1.{weight,bias}`          — dilated conv, sub-block s
//!   `vocoder_res_{i}_{j}_conv2.{weight,bias}`          — k=1 (post) conv
//!     where `i` = upsample stage, `j` = MRF resblock index, with the
//!     sub-block dilation index encoded into a flat `j_s` pair via
//!     [`vocoder_tensor_name`] when `indices.len() == 3`.
//!   `vocoder_conv_post.{weight,bias}`
//!
//! TODO: weight-norm folding for inference (multiply weight by g/||v|| at
//! load time). HiFi-GAN's published weights apply weight-norm to every conv;
//! for inference we expect the conversion pipeline to fold `g` into the raw
//! weight tensor so the kernel can ignore it. If the loader ships unfolded
//! weights, audio quality will degrade quietly — add a check at `new()`.

use std::collections::HashMap;
use std::sync::Arc;

use crate::loader::{KnotCodec, WeightBackend};
use crate::math::f16_to_f32;
use crate::math_pneuma::{conv1d, conv1d_out_len, conv_transpose1d};

// ─────────────────────────────────────────────────────────────────────────────
// Config
// ─────────────────────────────────────────────────────────────────────────────

/// Structural configuration for a HiFi-GAN-class vocoder.
///
/// All sizes are in elements (not bytes). Defaults track the published
/// HiFi-GAN V1 generator (Piper's default), which upsamples 80 Hz mel frames
/// to 22 050 Hz audio at a stride product of 256.
#[derive(Debug, Clone, PartialEq)]
pub struct VocoderConfig {
    /// Number of mel filterbank channels in the input. 80 to match Whisper /
    /// Piper.
    pub n_mels: usize,
    /// Channel count at the output of the initial pre-conv. Halved at each
    /// upsample stage. 512 for HiFi-GAN V1, 128 for V3 (small).
    pub initial_channels: usize,
    /// Stride for each transposed-conv upsample stage. The product must equal
    /// `sample_rate / mel_frame_rate` (e.g. 22 050 / ~86 ≈ 256 for V1).
    pub upsample_rates: Vec<usize>,
    /// Kernel size for each transposed-conv stage. Conventionally
    /// `2 * stride`; must be `>= stride` so the output is fully covered.
    pub upsample_kernel_sizes: Vec<usize>,
    /// Kernel sizes for the parallel ResBlock1s in the Multi-Receptive-Field
    /// (MRF) module. HiFi-GAN V1 uses `[3, 7, 11]`.
    pub resblock_kernels: Vec<usize>,
    /// Per-resblock dilation schedule. `resblock_dilations[k_idx]` lists the
    /// dilations of the dilated-conv sub-blocks inside ResBlock1
    /// `k_idx` (i.e. the one with `kernel = resblock_kernels[k_idx]`). HiFi-GAN
    /// V1 ships `[[1,3,5], [1,3,5], [1,3,5]]`.
    pub resblock_dilations: Vec<Vec<usize>>,
    /// Output sample rate, in Hz. Reported back to the caller for WAV writes.
    pub sample_rate: usize,
}

impl Default for VocoderConfig {
    /// Defaults to HiFi-GAN V1 (Piper-class small).
    fn default() -> Self {
        Self {
            n_mels: 80,
            initial_channels: 512,
            upsample_rates: vec![8, 8, 2, 2],
            upsample_kernel_sizes: vec![16, 16, 4, 4],
            resblock_kernels: vec![3, 7, 11],
            resblock_dilations: vec![vec![1, 3, 5], vec![1, 3, 5], vec![1, 3, 5]],
            sample_rate: 22_050,
        }
    }
}

/// Parse a [`VocoderConfig`] out of a `.knot` metadata blob.
///
/// Looks for a top-level `vocoder` object (or falls through to the root) with
/// the same field names as the struct. Missing fields fall back to the
/// HiFi-GAN V1 defaults in [`VocoderConfig::default`]. Mirrors the lenient
/// parsing style of [`crate::loader_whisper::parse_whisper_config`].
pub fn parse_vocoder_config(meta: &serde_json::Value) -> Result<VocoderConfig, String> {
    let cfg = meta
        .get("vocoder")
        .or_else(|| meta.get("config"))
        .unwrap_or(meta);
    if !cfg.is_object() {
        return Err("parse_vocoder_config: `vocoder`/`config` is not a JSON object".to_string());
    }
    let d = VocoderConfig::default();

    fn as_usize(v: &serde_json::Value) -> Option<usize> {
        v.as_u64().map(|n| n as usize)
    }
    fn as_usize_vec(v: &serde_json::Value) -> Option<Vec<usize>> {
        v.as_array()
            .map(|arr| arr.iter().filter_map(as_usize).collect::<Vec<_>>())
    }
    fn as_usize_vec2(v: &serde_json::Value) -> Option<Vec<Vec<usize>>> {
        v.as_array()
            .map(|arr| arr.iter().filter_map(as_usize_vec).collect::<Vec<_>>())
    }

    Ok(VocoderConfig {
        n_mels: cfg.get("n_mels").and_then(as_usize).unwrap_or(d.n_mels),
        initial_channels: cfg
            .get("initial_channels")
            .or_else(|| cfg.get("upsample_initial_channel"))
            .and_then(as_usize)
            .unwrap_or(d.initial_channels),
        upsample_rates: cfg
            .get("upsample_rates")
            .and_then(as_usize_vec)
            .unwrap_or(d.upsample_rates.clone()),
        upsample_kernel_sizes: cfg
            .get("upsample_kernel_sizes")
            .and_then(as_usize_vec)
            .unwrap_or(d.upsample_kernel_sizes.clone()),
        resblock_kernels: cfg
            .get("resblock_kernels")
            .or_else(|| cfg.get("resblock_kernel_sizes"))
            .and_then(as_usize_vec)
            .unwrap_or(d.resblock_kernels.clone()),
        resblock_dilations: cfg
            .get("resblock_dilations")
            .or_else(|| cfg.get("resblock_dilation_sizes"))
            .and_then(as_usize_vec2)
            .unwrap_or(d.resblock_dilations.clone()),
        sample_rate: cfg
            .get("sample_rate")
            .and_then(as_usize)
            .unwrap_or(d.sample_rate),
    })
}

// ─────────────────────────────────────────────────────────────────────────────
// Tensor name composition
// ─────────────────────────────────────────────────────────────────────────────

/// Compose a `.knot` tensor name for a vocoder weight.
///
/// `stage` examples and their `indices` shapes:
/// - `"conv_pre"` / `"conv_post"`: `indices = []`
/// - `"ups"`: `indices = [stage_i]`
/// - `"res_conv1"` / `"res_conv2"`: `indices = [stage_i, k_idx, sub_block_s]`
/// `role` is one of `"weight"`, `"bias"`.
///
/// Examples:
/// - `vocoder_tensor_name("conv_pre", &[], "weight")` → `"vocoder_conv_pre.weight"`
/// - `vocoder_tensor_name("ups", &[2], "bias")` → `"vocoder_ups_2.bias"`
/// - `vocoder_tensor_name("res_conv1", &[1, 0, 2], "weight")`
///   → `"vocoder_res_1_0_2_conv1.weight"`
pub fn vocoder_tensor_name(stage: &str, indices: &[usize], role: &str) -> String {
    // Trim a leading "res_" off conv1 / conv2 stages so the `_convN` suffix
    // appears after the indices, matching the spec format
    // `vocoder_res_{i}_{j}_conv1.weight`.
    let (base, suffix) = match stage {
        "res_conv1" => ("res", "_conv1"),
        "res_conv2" => ("res", "_conv2"),
        other => (other, ""),
    };
    let mut name = String::from("vocoder_");
    name.push_str(base);
    for idx in indices {
        name.push('_');
        name.push_str(&idx.to_string());
    }
    name.push_str(suffix);
    name.push('.');
    name.push_str(role);
    name
}

// ─────────────────────────────────────────────────────────────────────────────
// Cached tensor names
// ─────────────────────────────────────────────────────────────────────────────

/// Cached tensor names for one ResBlock1 sub-block (one dilation step inside
/// one MRF kernel inside one upsample stage).
///
/// Resolving these once at `new()` keeps the hot path allocation-free, the
/// same trick the Whisper encoder uses with its `EncoderBlockNames`.
#[derive(Debug, Clone)]
struct ResSubBlockNames {
    conv1_w: String,
    conv1_b: String,
    conv2_w: String,
    conv2_b: String,
}

/// Cached tensor names for one upsample stage (one transposed conv + a stack
/// of MRF resblocks).
#[derive(Debug, Clone)]
struct UpsampleStageNames {
    ups_w: String,
    ups_b: String,
    /// Outer index = MRF resblock (one per `resblock_kernels` entry).
    /// Inner index = sub-block within that resblock (one per dilation).
    resblocks: Vec<Vec<ResSubBlockNames>>,
}

/// Cached top-level (non-stage) tensor names. Resolved once at `new()`.
#[derive(Debug, Clone)]
struct VocoderTopNames {
    conv_pre_w: String,
    conv_pre_b: String,
    conv_post_w: String,
    conv_post_b: String,
}

impl VocoderTopNames {
    fn new() -> Self {
        Self {
            conv_pre_w: vocoder_tensor_name("conv_pre", &[], "weight"),
            conv_pre_b: vocoder_tensor_name("conv_pre", &[], "bias"),
            conv_post_w: vocoder_tensor_name("conv_post", &[], "weight"),
            conv_post_b: vocoder_tensor_name("conv_post", &[], "bias"),
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Vocoder
// ─────────────────────────────────────────────────────────────────────────────

/// HiFi-GAN-class vocoder: mel-spectrogram → f32 PCM at `config.sample_rate`.
///
/// Construction is cheap; weight bytes are fetched lazily per `forward()` via
/// the `backend`. Tensor names are pre-resolved at `new()` so the hot path
/// pays no `format!` cost per forward.
pub struct HiFiGANVocoder {
    config: VocoderConfig,
    backend: Arc<dyn WeightBackend>,
    codec: KnotCodec,
    /// Resident decoded tensor cache. Conv weights are immutable for a vocoder
    /// instance, so repeated forwards should not refetch/dequantize them.
    f32_tensor_cache: HashMap<String, Vec<f32>>,
    /// Per-upsample-stage tensor name cache.
    stages: Vec<UpsampleStageNames>,
    /// Top-level (pre-conv / post-conv) tensor name cache.
    top: VocoderTopNames,
}

impl HiFiGANVocoder {
    /// Construct a vocoder from a parsed config and a weight backend handle.
    ///
    /// Pre-resolves all tensor names. Validates that
    /// `upsample_rates.len() == upsample_kernel_sizes.len()` and that
    /// `resblock_kernels.len() == resblock_dilations.len()`; panics otherwise
    /// because the architecture is structurally inconsistent in that case.
    pub fn new(config: VocoderConfig, backend: Arc<dyn WeightBackend>) -> Self {
        Self::with_codec(config, backend, KnotCodec::Fp32)
    }

    /// Construct a vocoder with an explicit payload codec.
    pub fn with_codec(
        config: VocoderConfig,
        backend: Arc<dyn WeightBackend>,
        codec: KnotCodec,
    ) -> Self {
        assert_eq!(
            config.upsample_rates.len(),
            config.upsample_kernel_sizes.len(),
            "HiFiGANVocoder.new: upsample_rates ({}) and upsample_kernel_sizes ({}) must have the same length",
            config.upsample_rates.len(),
            config.upsample_kernel_sizes.len(),
        );
        assert_eq!(
            config.resblock_kernels.len(),
            config.resblock_dilations.len(),
            "HiFiGANVocoder.new: resblock_kernels ({}) and resblock_dilations ({}) must have the same length",
            config.resblock_kernels.len(),
            config.resblock_dilations.len(),
        );

        let stages = (0..config.upsample_rates.len())
            .map(|i| {
                let resblocks = (0..config.resblock_kernels.len())
                    .map(|j| {
                        config.resblock_dilations[j]
                            .iter()
                            .enumerate()
                            .map(|(s, _dilation)| ResSubBlockNames {
                                conv1_w: vocoder_tensor_name("res_conv1", &[i, j, s], "weight"),
                                conv1_b: vocoder_tensor_name("res_conv1", &[i, j, s], "bias"),
                                conv2_w: vocoder_tensor_name("res_conv2", &[i, j, s], "weight"),
                                conv2_b: vocoder_tensor_name("res_conv2", &[i, j, s], "bias"),
                            })
                            .collect::<Vec<_>>()
                    })
                    .collect::<Vec<_>>();
                UpsampleStageNames {
                    ups_w: vocoder_tensor_name("ups", &[i], "weight"),
                    ups_b: vocoder_tensor_name("ups", &[i], "bias"),
                    resblocks,
                }
            })
            .collect();

        Self {
            top: VocoderTopNames::new(),
            stages,
            config,
            backend,
            codec,
            f32_tensor_cache: HashMap::new(),
        }
    }

    /// Fetch a tensor and dequantize it to a f32 vector if it's fp16.
    fn fetch_f32(&mut self, name: &str) -> Vec<f32> {
        if let Some(cached) = self.f32_tensor_cache.get(name) {
            return cached.clone();
        }
        let bytes = self
            .backend
            .fetch_tensor(name)
            .unwrap_or_else(|e| panic!("Vocoder fetch {}: {}", name, e));
        let out = match self.codec {
            KnotCodec::Fp32 => bytes_to_f32_slice(&bytes).to_vec(),
            KnotCodec::Fp16 => {
                let numel = bytes.len() / 2;
                let mut out = vec![0.0f32; numel];
                for i in 0..numel {
                    let h = u16::from_le_bytes([bytes[i * 2], bytes[i * 2 + 1]]);
                    out[i] = f16_to_f32(h);
                }
                out
            }
        };
        self.f32_tensor_cache.insert(name.to_string(), out.clone());
        out
    }

    /// Clear resident decoded tensor cache.
    pub fn clear_weight_cache(&mut self) {
        self.f32_tensor_cache.clear();
    }

    /// Number of decoded tensors resident in the cache.
    pub fn weight_cache_len(&self) -> usize {
        self.f32_tensor_cache.len()
    }

    /// Run the vocoder forward.
    ///
    /// `mel`: row-major `(n_mels, n_frames)` mel-spectrogram. `n_frames` may be
    /// any positive value; the output length is `n_frames * prod(upsample_rates)`
    /// (less per-stage padding cropping; see [`crate::math_pneuma::conv_transpose1d`]).
    ///
    /// Returns: f32 PCM samples at `config.sample_rate`, mono, in [-1, 1].
    ///
    /// Panics if `mel.len()` is not a multiple of `n_mels`, or if any tensor
    /// fetched via the backend has the wrong byte length for its declared
    /// shape.
    pub fn forward(&mut self, mel: &[f32]) -> Vec<f32> {
        let cfg = self.config.clone();
        assert!(
            mel.len().is_multiple_of(cfg.n_mels),
            "HiFiGANVocoder.forward: mel length {} not a multiple of n_mels={}",
            mel.len(),
            cfg.n_mels,
        );
        let n_frames = mel.len() / cfg.n_mels;

        // ── 1. Initial conv: (n_mels, n_frames) → (initial_channels, n_frames)
        // k=7, stride=1, pad=3 preserves the time axis.
        let pre_k = 7usize;
        let pre_pad = 3usize;
        let pre_out_len = conv1d_out_len(n_frames, pre_k, 1, pre_pad);
        debug_assert_eq!(pre_out_len, n_frames, "pre-conv must preserve time axis");
        let mut x = vec![0.0f32; cfg.initial_channels * pre_out_len];
        {
            let pre_w_name = self.top.conv_pre_w.clone();
            let pre_b_name = self.top.conv_pre_b.clone();
            let pre_w = self.fetch_f32(&pre_w_name);
            let pre_b = self.fetch_f32(&pre_b_name);
            conv1d(
                &mut x,
                mel,
                &pre_w,
                Some(&pre_b),
                cfg.n_mels,
                cfg.initial_channels,
                n_frames,
                pre_k,
                1,
                pre_pad,
            );
        }
        let mut x_len = pre_out_len;
        let mut x_channels = cfg.initial_channels;

        // ── 2. Upsample stages with MRF fusion ──────────────────────────────
        for i in 0..cfg.upsample_rates.len() {
            let stride = cfg.upsample_rates[i];
            let k = cfg.upsample_kernel_sizes[i];
            // Standard HiFi-GAN padding for the transposed conv: (k - stride) / 2.
            // This keeps the upsampled length close to `x_len * stride`. Asymmetric
            // pad (when k - stride is odd) is handled by truncating the output to
            // exactly `x_len * stride`; HiFi-GAN's reference does the same.
            let pad = (k.saturating_sub(stride)) / 2;
            let out_channels = x_channels / 2;

            // leaky_relu(0.1) on the input to the upsample.
            leaky_relu_inplace(&mut x, 0.1);

            // Compute output length per the conv_transpose1d formula, then
            // optionally crop to `x_len * stride` to undo the asymmetric pad
            // tail (see comment above).
            let span = (x_len.saturating_sub(1)) * stride + k;
            let raw_out_len = span.saturating_sub(2 * pad);
            let target_len = x_len * stride;
            let mut up = vec![0.0f32; out_channels * raw_out_len];
            {
                let ups_w_name = self.stages[i].ups_w.clone();
                let ups_b_name = self.stages[i].ups_b.clone();
                let ups_w = self.fetch_f32(&ups_w_name);
                let ups_b = self.fetch_f32(&ups_b_name);
                conv_transpose1d(
                    &mut up,
                    &x,
                    &ups_w,
                    Some(&ups_b),
                    x_channels,
                    out_channels,
                    x_len,
                    k,
                    stride,
                    pad,
                );
            }
            let up_len = if raw_out_len >= target_len {
                // Crop to target_len (drop trailing samples).
                let mut cropped = vec![0.0f32; out_channels * target_len];
                for c in 0..out_channels {
                    let src = &up[c * raw_out_len..c * raw_out_len + target_len];
                    cropped[c * target_len..(c + 1) * target_len].copy_from_slice(src);
                }
                up = cropped;
                target_len
            } else {
                raw_out_len
            };

            // Multi-Receptive-Field fusion: average of N parallel ResBlock1
            // outputs over the upsampled tensor.
            let mut fused = vec![0.0f32; out_channels * up_len];
            let n_resblocks = cfg.resblock_kernels.len();
            for j in 0..n_resblocks {
                let rk = cfg.resblock_kernels[j];
                let dilations = &cfg.resblock_dilations[j];
                let mut h = up.clone();
                for (s, &dilation) in dilations.iter().enumerate() {
                    let names = self.stages[i].resblocks[j][s].clone();
                    self.resblock_subblock(&mut h, out_channels, up_len, rk, dilation, &names);
                }
                // Accumulate into fused.
                for (f, v) in fused.iter_mut().zip(h.iter()) {
                    *f += *v;
                }
            }
            let scale = 1.0 / (n_resblocks as f32);
            for f in fused.iter_mut() {
                *f *= scale;
            }

            x = fused;
            x_len = up_len;
            x_channels = out_channels;
        }

        // ── 3. Final conv: (final_channels, x_len) → (1, x_len) → tanh ──────
        leaky_relu_inplace(&mut x, 0.1);
        let post_k = 7usize;
        let post_pad = 3usize;
        let post_out_len = conv1d_out_len(x_len, post_k, 1, post_pad);
        debug_assert_eq!(post_out_len, x_len, "post-conv must preserve time axis");
        let mut audio = vec![0.0f32; post_out_len];
        {
            let post_w_name = self.top.conv_post_w.clone();
            let post_b_name = self.top.conv_post_b.clone();
            let post_w = self.fetch_f32(&post_w_name);
            let post_b = self.fetch_f32(&post_b_name);
            conv1d(
                &mut audio,
                &x,
                &post_w,
                Some(&post_b),
                x_channels,
                1,
                x_len,
                post_k,
                1,
                post_pad,
            );
        }
        for v in audio.iter_mut() {
            *v = v.tanh();
        }
        audio
    }

    /// One sub-block of a ResBlock1 (HiFi-GAN naming):
    ///   x ← x + conv2(leaky_relu(conv1(leaky_relu(x), dilation=d)))
    /// where conv2 is k-wide with dilation=1. Operates over the full
    /// (channels, time) tensor in `h`.
    fn resblock_subblock(
        &mut self,
        h: &mut Vec<f32>,
        channels: usize,
        time: usize,
        kernel: usize,
        dilation: usize,
        names: &ResSubBlockNames,
    ) {
        // Padding to keep length constant under a dilated conv:
        //   pad = dilation * (kernel - 1) / 2
        // Requires `kernel` odd (it is — 3, 7, 11 in V1).
        debug_assert!(
            kernel % 2 == 1,
            "resblock kernel must be odd, got {}",
            kernel
        );

        // Residual snapshot.
        let residual = h.clone();

        // ── conv1: dilated. We don't have native dilation in conv1d, so
        // express it by inserting (dilation - 1) zeros between kernel taps:
        // build an effective kernel of size `(kernel - 1) * dilation + 1` with
        // the original taps at positions `[0, dilation, 2*dilation, ...]`. The
        // extra cost is negligible for V1's dilations of 1/3/5.
        let pad1 = dilation * (kernel - 1) / 2;
        leaky_relu_inplace(h, 0.1);
        {
            let w_dense = self.fetch_f32(&names.conv1_w);
            let b = self.fetch_f32(&names.conv1_b);
            // Expand to the dilated layout in a scratch buffer.
            let eff_k = (kernel - 1) * dilation + 1;
            let mut w_dilated = vec![0.0f32; channels * channels * eff_k];
            for oc in 0..channels {
                for ic in 0..channels {
                    for kk in 0..kernel {
                        let src = w_dense[(oc * channels + ic) * kernel + kk];
                        w_dilated[(oc * channels + ic) * eff_k + kk * dilation] = src;
                    }
                }
            }
            let out_len = conv1d_out_len(time, eff_k, 1, pad1);
            debug_assert_eq!(out_len, time, "dilated conv1 must preserve time axis");
            let mut tmp = vec![0.0f32; channels * out_len];
            conv1d(
                &mut tmp,
                h,
                &w_dilated,
                Some(&b),
                channels,
                channels,
                time,
                eff_k,
                1,
                pad1,
            );
            *h = tmp;
        }

        // ── conv2: kernel `k`, dilation=1 ─────────────────────────────────
        let pad2 = (kernel - 1) / 2;
        leaky_relu_inplace(h, 0.1);
        {
            let w = self.fetch_f32(&names.conv2_w);
            let b = self.fetch_f32(&names.conv2_b);
            let out_len = conv1d_out_len(time, kernel, 1, pad2);
            debug_assert_eq!(out_len, time, "conv2 must preserve time axis");
            let mut tmp = vec![0.0f32; channels * out_len];
            conv1d(
                &mut tmp,
                h,
                &w,
                Some(&b),
                channels,
                channels,
                time,
                kernel,
                1,
                pad2,
            );
            *h = tmp;
        }

        // ── Residual add ──────────────────────────────────────────────────
        debug_assert_eq!(h.len(), residual.len(), "residual shape mismatch");
        for (v, r) in h.iter_mut().zip(residual.iter()) {
            *v += *r;
        }
    }

    /// Borrow the parsed config (e.g. for sample rate when writing WAV).
    pub fn config(&self) -> &VocoderConfig {
        &self.config
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Local helpers
// ─────────────────────────────────────────────────────────────────────────────

/// Leaky ReLU in-place. `slope` is the negative-side gradient; HiFi-GAN uses
/// 0.1 throughout.
#[inline]
fn leaky_relu_inplace(x: &mut [f32], slope: f32) {
    for v in x.iter_mut() {
        if *v < 0.0 {
            *v *= slope;
        }
    }
}

/// View raw little-endian f32 bytes returned by `WeightBackend::fetch_tensor`
/// as an f32 slice without copying. Mirrors the helper in
/// [`crate::model_whisper_encoder`]; kept private here to keep this file
/// self-contained.
#[inline(always)]
fn bytes_to_f32_slice(bytes: &[u8]) -> &[f32] {
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}

// ─────────────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;
    use crate::loader::OwnedBytes;
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::sync::Arc;

    #[test]
    fn tensor_name_basic() {
        assert_eq!(
            vocoder_tensor_name("conv_pre", &[], "weight"),
            "vocoder_conv_pre.weight"
        );
        assert_eq!(
            vocoder_tensor_name("conv_post", &[], "bias"),
            "vocoder_conv_post.bias"
        );
        assert_eq!(
            vocoder_tensor_name("ups", &[2], "bias"),
            "vocoder_ups_2.bias"
        );
        assert_eq!(
            vocoder_tensor_name("res_conv1", &[1, 0, 2], "weight"),
            "vocoder_res_1_0_2_conv1.weight"
        );
        assert_eq!(
            vocoder_tensor_name("res_conv2", &[3, 2, 0], "bias"),
            "vocoder_res_3_2_0_conv2.bias"
        );
    }

    #[test]
    fn default_config_shapes() {
        let c = VocoderConfig::default();
        assert_eq!(c.upsample_rates.iter().product::<usize>(), 256);
        assert_eq!(c.upsample_rates.len(), c.upsample_kernel_sizes.len());
        assert_eq!(c.resblock_kernels.len(), c.resblock_dilations.len());
        assert_eq!(c.sample_rate, 22_050);
    }

    #[test]
    fn leaky_relu_negative_only() {
        let mut x = vec![-2.0_f32, -0.5, 0.0, 0.5, 2.0];
        leaky_relu_inplace(&mut x, 0.1);
        assert!((x[0] - (-0.2)).abs() < 1e-6);
        assert!((x[1] - (-0.05)).abs() < 1e-6);
        assert!((x[2] - 0.0).abs() < 1e-6);
        assert!((x[3] - 0.5).abs() < 1e-6);
        assert!((x[4] - 2.0).abs() < 1e-6);
    }

    #[test]
    fn parse_config_with_overrides() {
        let meta = serde_json::json!({
            "vocoder": {
                "n_mels": 80,
                "initial_channels": 128,
                "upsample_rates": [8, 8, 4],
                "upsample_kernel_sizes": [16, 16, 8],
                "resblock_kernels": [3, 5],
                "resblock_dilations": [[1, 3], [1, 3]],
                "sample_rate": 16000
            }
        });
        let cfg = parse_vocoder_config(&meta).unwrap();
        assert_eq!(cfg.initial_channels, 128);
        assert_eq!(cfg.upsample_rates, vec![8, 8, 4]);
        assert_eq!(cfg.resblock_kernels, vec![3, 5]);
        assert_eq!(cfg.resblock_dilations, vec![vec![1, 3], vec![1, 3]]);
        assert_eq!(cfg.sample_rate, 16000);
    }

    #[test]
    fn parse_config_falls_back_to_defaults() {
        let meta = serde_json::json!({});
        let cfg = parse_vocoder_config(&meta).unwrap();
        assert_eq!(cfg, VocoderConfig::default());
    }

    struct CountingBackend {
        fetch_count: Arc<AtomicUsize>,
        bytes: Vec<u8>,
    }

    impl WeightBackend for CountingBackend {
        fn fetch_tensor(&self, _name: &str) -> Result<OwnedBytes, String> {
            self.fetch_count.fetch_add(1, Ordering::Relaxed);
            Ok(OwnedBytes::Owned(Arc::new(self.bytes.clone())))
        }

        fn has_tensor(&self, _name: &str) -> bool {
            true
        }

        fn as_any(&self) -> &dyn std::any::Any {
            self
        }
    }

    #[test]
    fn fetch_f32_reuses_resident_decoded_tensor_cache() {
        let fetch_count = Arc::new(AtomicUsize::new(0));
        let mut bytes = Vec::new();
        for value in [1.0_f32, 2.0, 3.0, 4.0] {
            bytes.extend_from_slice(&value.to_le_bytes());
        }
        let backend = Arc::new(CountingBackend {
            fetch_count: Arc::clone(&fetch_count),
            bytes,
        });
        let mut vocoder = HiFiGANVocoder::new(VocoderConfig::default(), backend);

        let first = vocoder.fetch_f32("vocoder_conv_pre.weight");
        let second = vocoder.fetch_f32("vocoder_conv_pre.weight");

        assert_eq!(first, second);
        assert_eq!(fetch_count.load(Ordering::Relaxed), 1);
        assert_eq!(vocoder.weight_cache_len(), 1);

        vocoder.clear_weight_cache();
        let _third = vocoder.fetch_f32("vocoder_conv_pre.weight");
        assert_eq!(fetch_count.load(Ordering::Relaxed), 2);
    }
}
